// Source-of-truth Bicep. The candidate edits this file (and ideally
// regenerates infra/main.json via tools/bicep_to_json.py), but the Python
// test suite reads infra/main.json so the harness stays offline.

param location string = 'eastus2'
param clusterName string = 'checkout-platform'
param clusterVersion string = '1.29.0'
param nodePoolVersion string = '1.28.5'  // BUG: should be aligned to clusterVersion
param nodeResourceGroupName string = 'MC_checkout_${clusterName}_${location}'

resource clusterIdentity 'Microsoft.ManagedIdentity/userAssignedIdentities@2023-01-31' = {
  name: 'aksClusterIdentity'
  location: location
}

resource aks 'Microsoft.ContainerService/managedClusters@2024-02-01' = {
  name: clusterName
  location: location
  identity: { type: 'UserAssigned', userAssignedIdentities: { '${clusterIdentity.id}': {} } }
  properties: {
    kubernetesVersion: clusterVersion
    nodeResourceGroup: nodeResourceGroupName
    agentPoolProfiles: [
      { name: 'system', count: 3, vmSize: 'Standard_D4s_v5', mode: 'System', orchestratorVersion: nodePoolVersion }
      { name: 'payments', count: 3, vmSize: 'Standard_D4s_v5', mode: 'User', orchestratorVersion: nodePoolVersion }
    ]
  }
}

// BUG: this role assignment was removed in the recent PR. Without
// Network Contributor on the MC_ resource group, AKS cannot manage
// LoadBalancers / Public IPs / NSGs there.
// resource clusterNetworkContributor ... (deleted)

resource clusterSubnetNsg 'Microsoft.Network/networkSecurityGroups@2023-09-01' = {
  name: 'cluster-subnet-nsg'
  location: location
  properties: {
    securityRules: [
      // BUG: this rule was added in the recent PR and denies all 443 outbound.
      { name: 'tightened-443-out', properties: { access: 'Deny', direction: 'Outbound', protocol: 'Tcp', destinationPortRange: '443', priority: 100, sourceAddressPrefix: '*', destinationAddressPrefix: '*', sourcePortRange: '*' } }
    ]
  }
}

