from infra_assertions import resources_of_type


def test_cluster_subnet_nsg_does_not_block_443_outbound(arm):
    nsgs = resources_of_type(arm, 'Microsoft.Network/networkSecurityGroups')
    cluster_nsg = next((n for n in nsgs if n.get('name') == 'cluster-subnet-nsg'), None)
    assert cluster_nsg is not None, 'cluster-subnet-nsg must exist'
    rules = (cluster_nsg.get('properties') or {}).get('securityRules', [])
    bad_rules = []
    for rule in rules:
        rprops = (rule.get('properties') or {})
        if (
            rprops.get('direction') == 'Outbound'
            and rprops.get('access') == 'Deny'
            and (rprops.get('protocol') == 'Tcp' or rprops.get('protocol') == '*')
            and str(rprops.get('destinationPortRange') or '') in {'443', '*'}
        ):
            bad_rules.append(rule.get('name'))
    assert not bad_rules, (
        f'cluster-subnet-nsg must not deny outbound TCP 443 (would block AKS API + MCR + STS); '
        f'offending rule(s): {bad_rules}'
    )
